### 1. Create `src/pages/dashboard/components/StatsRow.jsx`
Two large stat cards side by side:
```jsx
import React from "react";
import { Card, Row, Col } from "antd";

const stats = [
  { title: "Giáo viên", value: "2.000.000 ₫", subtitle: "Tổng doanh thu", icon: "👨‍🏫", color: "#8B5CF6" },
  { title: "Học viên", value: "2.000.000 ₫", subtitle: "Tổng doanh thu", icon: "👨‍🎓", color: "#10B981" },
];

const StatsRow = () => (
  <Row gutter={[16, 16]} className="mb-4">
    {stats.map((s, i) => (
      <Col xs={24} sm={12} key={i}>
        <Card style={{ borderRadius: 12, boxShadow: "0 2px 8px rgba(0,0,0,0.08)" }}>
          <div style={{ display: "flex", alignItems: "center", gap: 16 }}>
            <div style={{ fontSize: 40 }}>{s.icon}</div>
            <div>
              <div style={{ fontSize: 24, fontWeight: 700, color: s.color }}>{s.value}</div>
              <div style={{ color: "#666", fontSize: 14 }}>{s.subtitle}</div>
              <div style={{ fontWeight: 600, fontSize: 16 }}>{s.title}</div>
            </div>
          </div>
        </Card>
      </Col>
    ))}
  </Row>
);

export default StatsRow;
```

### 2. Create `src/pages/dashboard/components/CalendarSection.jsx`
Calendar schedule grid with toggle between grid and list view:
```jsx
import React, { useState } from "react";
import { Card, Row, Col, Button, Tag, Tabs } from "antd";

const mockSchedules = [
  { id: 1, date: "20/04", day: "T2", time: "08:00 - 10:00", course: "Khoá A1 - Nền tảng", status: "Đã đăng ký", color: "blue" },
  { id: 2, date: "20/04", day: "T2", time: "14:00 - 16:00", course: "Khoá B2 - Nâng cao", status: "Chờ xác nhận", color: "orange" },
  { id: 3, date: "21/04", day: "T3", time: "08:00 - 10:00", course: "Khoá A2 - Cơ bản", status: "Đã đăng ký", color: "blue" },
  { id: 4, date: "22/04", day: "T4", time: "10:00 - 12:00", course: "Khoá A1 - Nâng cao", status: "Đã hoàn thành", color: "green" },
  { id: 5, date: "23/04", day: "T5", time: "08:00 - 10:00", course: "Khoá B1 - Thực hành", status: "Đã đăng ký", color: "blue" },
  { id: 6, date: "24/04", day: "T6", time: "14:00 - 16:00", course: "Khoá A2 - Lý thuyết", status: "Chờ xác nhận", color: "orange" },
];

const CalendarSection = () => {
  const [view, setView] = useState("grid");

  return (
    <Card 
      title={<span style={{ fontWeight: 700, fontSize: 16 }}>📅 Lịch học / Lịch thi</span>}
      extra={<Button>+ Thêm</Button>}
      style={{ borderRadius: 12, marginBottom: 24 }}
      className="shadow-sm"
    >
      <div style={{ marginBottom: 12 }}>
        <Button.Group>
          <Button type={view === "grid" ? "primary" : "default"} onClick={() => setView("grid")}>▦ Grid</Button>
          <Button type={view === "list" ? "primary" : "default"} onClick={() => setView("list")}>☰ Danh sách</Button>
        </Button.Group>
      </div>

      {view === "grid" ? (
        <Row gutter={[12, 12]}>
          {mockSchedules.slice(0, 6).map((s) => (
            <Col xs={24} sm={12} md={8} key={s.id}>
              <div style={{ 
                border: "1px solid #eee", borderRadius: 10, padding: 14,
                background: "#fff", position: "relative"
              }}>
                <div style={{ 
                  position: "absolute", top: 0, left: 0, 
                  background: s.color === "blue" ? "#1890ff" : s.color === "orange" ? "#fa8c16" : "#52c41a",
                  color: "#fff", padding: "2px 8px", borderRadius: "10px 0 10px 0",
                  fontSize: 12, fontWeight: 600
                }}>
                  {s.date} - {s.day}
                </div>
                <div style={{ marginTop: 32, fontSize: 13, color: "#333", fontWeight: 600, lineHeight: 1.4 }}>
                  {s.course}
                </div>
                <div style={{ fontSize: 12, color: "#999", marginTop: 4 }}>{s.time}</div>
                <Tag color={s.color} style={{ marginTop: 8 }}>{s.status}</Tag>
              </div>
            </Col>
          ))}
        </Row>
      ) : (
        <div style={{ overflowX: "auto" }}>
          <table style={{ width: "100%", borderCollapse: "collapse", fontSize: 14 }}>
            <thead>
              <tr style={{ background: "#f5f5f5" }}>
                <th style={{ padding: "8px 12px", textAlign: "left" }}>Ngày</th>
                <th style={{ padding: "8px 12px", textAlign: "left" }}>Ca học</th>
                <th style={{ padding: "8px 12px", textAlign: "left" }}>Khoá học</th>
                <th style={{ padding: "8px 12px", textAlign: "left" }}>Trạng thái</th>
              </tr>
            </thead>
            <tbody>
              {mockSchedules.map((s) => (
                <tr key={s.id} style={{ borderBottom: "1px solid #f0f0f0" }}>
                  <td style={{ padding: "10px 12px" }}>{s.date} - {s.day}</td>
                  <td style={{ padding: "10px 12px" }}>{s.time}</td>
                  <td style={{ padding: "10px 12px", fontWeight: 600 }}>{s.course}</td>
                  <td style={{ padding: "10px 12px" }}><Tag color={s.color}>{s.status}</Tag></td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </Card>
  );
};

export default CalendarSection;
```

### 3. Create `src/pages/dashboard/components/CostTable.jsx`
