    title: "Số tiền", 
    dataIndex: "amount", 
    key: "amount", 
    width: 150,
    render: (v) => <span style={{ color: "#ff4d4f", fontWeight: 600 }}>{v}</span>
  },
  { title: "Ghi chú", dataIndex: "note", key: "note" },
];

