import React, { useState } from "react";
import StudentChart from "./StudentChart";
import TeacherChart from "./TeacherChart";
import PaymentPieChart from "./PaymentPieChart";
import DebtChart from "./DebtChart";
import RevenueChart from "./RevenueChart";
import ListCard from "./card/ListCard";
import DateFilter from "../../../components/DateFilter";
import { useDispatch } from "react-redux";
import { setFilterDashboard } from "../../../stores/slices/dashboard.slice";
import AgentFilter from "../../../components/AgentFilter";
import StatsRow from "./components/StatsRow";
import CalendarSection from "./components/CalendarSection";
import CostTable from "./components/CostTable";
import DriverInfo from "./components/DriverInfo";

const ChartsDashboard = () => {
  const dispatch = useDispatch();
  const [agent, setAgent] = useState();

  const handleSetFilter = (filter) => {
    dispatch(setFilterDashboard(filter));
  };

  return (
    <>
      <div className="card">
        <div className="card-body">
          <div className="row g-3">
            <div className="col-12 col-sm-6 col-md-2">
              <div className="w-100">
                <DateFilter onChange={handleSetFilter} />
              </div>
            </div>

            <div className="col-12 col-sm-6 col-md-2">
              <div className="w-100">
                <AgentFilter
                  agent={agent}
                  setAgent={setAgent}
                  onChange={handleSetFilter}
                />
              </div>
            </div>
          </div>
        </div>
      </div>
      <StatsRow />
      <CalendarSection />
      <CostTable />
      <DriverInfo />
      <div className="col-12 mb-4">
        <ListCard />
      </div>
      <div className="col-12 mb-4">
        <RevenueChart />
      </div>
      <div className="row">
        <div className="col-12 col-xl-4 col-md-12">
          <StudentChart />
        </div>
        <div className="col-12 col-xl-4 col-md-12">
          <TeacherChart />
        </div>
        <div className="col-12 col-xl-4 col-md-12">
          <DebtChart />
        </div>
      </div>
    </>
  );
};

export default ChartsDashboard;

